---
import BaseLayout from '../layouts/BaseLayout.astro';
import { getCollection } from 'astro:content';
import { paths, type Locale } from '../i18n';
import { personJsonLd, websiteJsonLd } from '../site';
const { locale } = Astro.props as { locale: Locale };
const pt = locale === 'pt';
const p = paths[locale];
const recent = (await getCollection('posts', ({ data }) => data.locale === locale))
  .sort((a, b) => b.data.published.valueOf() - a.data.published.valueOf())
  .slice(0, 3);
const blogPrefix = pt ? '/blog/' : '/en/blog/';
const copy = pt ? {
  title: 'Elzo Brito — IA aplicada, automação e governança',
  description: 'Hub de projetos, consultoria e pesquisa de Elzo Brito em IA aplicada, automação e governança de agentes.',
  alternate: '/en/', eyebrow: 'Pesquisador · Arquiteto · Consultor',
  headline: 'Sistemas inteligentes precisam de direção, não apenas velocidade.',
  lede: 'Transformo IA em sistemas auditáveis, experiências de aprendizagem e decisões que equipes conseguem compreender e sustentar.',
  projects: 'Projetos que conectam pesquisa e prática', projectsText: 'Protocolos, produtos e métodos construídos para funcionar fora da apresentação.',
  consulting: 'Consultoria aplicada', consultingText: 'Estratégia, prototipagem e implantação de IA com governança e revisão humana.',
  blog: 'Caderno aberto', blogText: 'Notas sobre agentes, educação, sistemas e o trabalho de tornar tecnologia explicável.',
  about: 'Tecnologia com contexto', aboutText: 'Atuo na interseção entre Inteligência Artificial, engenharia de software e educação. Meu trabalho combina pesquisa, implementação e governança para reduzir a distância entre uma boa demonstração e um sistema confiável.',
  contact: 'Vamos conversar?', contactText: 'Se o desafio envolve IA aplicada, agentes ou automação com responsabilidade, posso ajudar a transformar a pergunta em um caminho executável.',
  recent: 'Do caderno', recentCta: 'Ver todos os artigos',
} : {
  title: 'Elzo Brito — Applied AI, automation and governance',
  description: 'Elzo Brito’s hub for projects, consulting and research in applied AI, automation and agent governance.',
  alternate: '/', eyebrow: 'Researcher · Architect · Consultant',
  headline: 'Intelligent systems need direction, not only speed.',
  lede: 'I turn AI into auditable systems, learning experiences and decisions that teams can understand and sustain.',
  projects: 'Projects connecting research and practice', projectsText: 'Protocols, products and methods designed to work beyond the presentation.',
  consulting: 'Applied consulting', consultingText: 'Strategy, prototyping and AI delivery with governance and human review.',
  blog: 'Open notebook', blogText: 'Notes on agents, education, systems and the work of making technology explainable.',
  about: 'Technology with context', aboutText: 'I work at the intersection of Artificial Intelligence, software engineering and education. My practice combines research, implementation and governance to close the gap between a compelling demo and a dependable system.',
  contact: 'Shall we talk?', contactText: 'If your challenge involves applied AI, agents or responsible automation, I can help turn the question into an executable path.',
  recent: 'From the notebook', recentCta: 'All articles',
};
---
<BaseLayout title={copy.title} description={copy.description} locale={locale} alternate={copy.alternate} jsonLd={[websiteJsonLd(), personJsonLd()]}>
  <section class="hero wrap">
    <p class="eyebrow">{copy.eyebrow}</p>
    <h1>{copy.headline}</h1>
    <p class="lede">{copy.lede}</p>
    <div class="actions"><a class="button" href="#projetos">{pt ? 'Explorar projetos' : 'Explore projects'} <span>↘</span></a><a class="button secondary" href="#contato">{pt ? 'Entrar em contato' : 'Get in touch'}</a></div>
  </section>
  <section class="section wrap" id="projetos">
    <div class="section-heading"><div><p class="eyebrow">01 — {pt ? 'Projetos' : 'Projects'}</p><h2>{copy.projects}</h2></div><p>{copy.projectsText}</p></div>
    <div class="grid">
      <a class="card esaa-card" href={p.esaa}><span class="tag">OPEN PROTOCOL</span><h3>ESAA</h3><p>{pt ? 'Event Sourcing para agentes autônomos: intenção, contrato, evidência e replay.' : 'Event Sourcing for autonomous agents: intent, contract, evidence and replay.'}</p></a>
      <a class="card consulting-card" href={p.consulting}><span class="tag">APPLIED AI</span><h3>{copy.consulting}</h3><p>{copy.consultingText}</p></a>
      <a class="card blog-card" href={p.blog}><span class="tag">FIELD NOTES</span><h3>{copy.blog}</h3><p>{copy.blogText}</p></a>
    </div>
  </section>
  {recent.length > 0 && (
    <section class="section wrap recent-posts" aria-label={copy.recent}>
      <div class="section-heading">
        <div>
          <p class="eyebrow">01b — Blog</p>
          <h2>{copy.recent}</h2>
        </div>
        <a class="recent-all" href={p.blog}>{copy.recentCta} ↗</a>
      </div>
      <div class="recent-grid">
        {recent.map((post) => {
          const slug = post.id.split('/').pop();
          return (
            <article class="recent-card">
              <p class="meta">
                {post.data.published.toLocaleDateString(pt ? 'pt-BR' : 'en-US', {
                  year: 'numeric',
                  month: 'short',
                  day: 'numeric',
                })}
              </p>
              <h3><a href={`${blogPrefix}${slug}/`}>{post.data.title}</a></h3>
              <p>{post.data.description}</p>
            </article>
          );
        })}
      </div>
    </section>
  )}
  <span id="atuacao" class="anchor-alias"></span><span id="consultorias" class="anchor-alias"></span><span id="pesquisa" class="anchor-alias"></span>
  <section class="section about-section" id="sobre">
    <div class="wrap about-grid">
      <div class="about-heading"><p class="eyebrow">02 — {pt ? 'Sobre' : 'About'}</p><h2>{copy.about}</h2></div>
      <div class="about-content"><p class="about-copy">{copy.aboutText}</p><div class="mini-links"><a href="https://github.com/elzobrito">GitHub ↗</a><a href="https://www.linkedin.com/in/elzobrito">LinkedIn ↗</a></div></div>
    </div>
  </section>
  <section class="section wrap contact-section" id="contato">
    <p class="eyebrow">03 — {pt ? 'Contato' : 'Contact'}</p><h2>{copy.contact}</h2><p>{copy.contactText}</p><div class="contact-links"><a class="contact-link" href="mailto:elzobrito@gmail.com">elzobrito@gmail.com ↗</a><a class="contact-social" href="https://twitter.com/elzobrito" rel="me">Twitter @elzobrito ↗</a></div>
  </section>
</BaseLayout>
<style>
  .esaa-card { box-shadow: inset 0 5px 0 var(--esaa); }.consulting-card{box-shadow:inset 0 5px 0 var(--consulting)}.blog-card{box-shadow:inset 0 5px 0 var(--blog)}
  .recent-posts .section-heading{align-items:end}.recent-all{font-family:var(--mono);font-size:.75rem;text-decoration:none;white-space:nowrap}.recent-grid{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:1.5rem;margin-top:2rem}.recent-card{border:1px solid var(--line);border-radius:14px;padding:1.4rem;background:var(--surface)}.recent-card .meta{font-family:var(--mono);font-size:.68rem;color:var(--muted)}.recent-card h3{font-family:var(--serif);font-size:1.35rem;line-height:1.15;margin:.7rem 0}.recent-card h3 a{text-decoration:none}.recent-card>p:last-child{color:var(--muted);font-size:.95rem}
  .about-section { background: var(--ink); color: var(--paper); margin-top: 4rem; }.about-grid{display:grid;grid-template-columns:minmax(240px,.85fr) minmax(0,1.15fr);gap:clamp(2rem,7vw,8rem);align-items:end}.about-heading h2{max-width:560px}.about-section .eyebrow{color:#f0a06f}.about-copy{font-size:clamp(1.15rem,2vw,1.5rem);max-width:700px;color:#c9c5bb;margin:0}.mini-links{display:flex;flex-wrap:wrap;gap:1.3rem;margin-top:2rem}.contact-section{text-align:center;max-width:900px}.contact-section p:not(.eyebrow){max-width:650px;margin:1rem auto;color:var(--muted);font-size:1.15rem}.contact-links{display:flex;flex-direction:column;align-items:center;gap:1.25rem;margin-top:2rem}.contact-link{font-family:var(--serif);display:inline-block;font-size:clamp(1.5rem,5vw,4rem)}.contact-social{display:inline-flex;padding:.65rem 1rem;border:1px solid var(--line);border-radius:999px;text-decoration:none;font-weight:700}.contact-social:hover{border-color:var(--accent);color:var(--accent)}.anchor-alias{display:block;position:relative;top:-80px;visibility:hidden}
  @media(max-width:800px){.about-grid{grid-template-columns:1fr;align-items:start}.about-content{max-width:700px}.recent-grid{grid-template-columns:1fr}}
</style>
